```class Solution {
    public long maxGCDScore(int[] nums, int k) {
        int n = nums.length;
        int maxScore = 1;
        int gcdScore = 1;

        for (int i = 0; i < n - k; i++) {
            int currentScore = 1;
            for (int j = i; j < n; j++) {
                if (nums[j] % gcd(nums[i], nums[j]) == 0) {
                    currentScore *= nums[j];
                }
            }
            maxScore = Math.max(maxScore, currentScore);
            gcdScore = Math.max(gcdScore, currentScore);
        }
        return maxScore;
    }

    public int gcd(int a, int b) {
        if (b == 0) {
            return a;
        }
        return gcd(b, a % b);
    }
}
